void ft_print_combn(int n) {
    int a[10], i;
    for (i = 0; i < n; i++)
        a[i] = i;
    while (1) {
        print(a, n);
        if (a[0] == 10 - n)
            break;
        ft_putchar(',');
        ft_putchar(' ');
        i = n - 1;
        while (a[i] == 9 - (n - 1 - i))
            i--;
        a[i]++;
        while (++i < n)
            a[i] = a[i - 1] + 1;
    }
}

