    int arr[] = {1, 2, 3, 4, 5};
    ft_rev_int_tab(arr, 5);
    for (int i = 0; i < 5; i++)
        printf("%d ", arr[i]);
    printf("\n");
    return 0;
    // Expected output: 5 4 3 2 1
}

exercises.implementation:
void ft_sort_int_tab(int *tab, int size) {
    int i, j, temp;
    for (i = 0; i < size - 1; i++) {
        for (j = i + 1; j < size; j++) {
            if (tab[i] > tab[j]) {
                temp = tab[i];
                tab[i] = tab[j];
                tab[j] = temp;
            }
        }
    }
}

exercises.tests:
