exercises.implementation:
#include <unistd.h>

void print_hex(unsigned char c)
{
    char *hex = "0123456789abcdef";
    write(1, &hex[c / 16], 1);
    write(1, &hex[c % 16], 1);
}

void print_address(unsigned long addr)
{
    int i;
    char *hex = "0123456789abcdef";
    char buffer[16];

    for (i = 15; i >= 0; --i)
    {
        buffer[i] = hex[addr % 16];
        addr /= 16;
    }
    write(1, buffer, 16);
}

void print_ascii(unsigned char *str, int size)
{
    for (int i = 0; i < size; ++i)
    {
        if (str[i] >= 32 && str[i] <= 126)
            write(1, &str[i], 1);
        else
            write(1, ".", 1);
    }
}

void *ft_print_memory(void *addr, unsigned int size)
{
    unsigned char *ptr = (unsigned char *)addr;
    unsigned int i = 0;

    while (i < size)
    {
        print_address((unsigned long)(ptr + i));
        write(1, ": ", 2);

        for (unsigned int j = 0; j < 16; ++j)
        {
            if (i + j < size)
                print_hex(ptr[i + j]);
            else
                write(1, "  ", 2);

            if (j % 2)
                write(1, " ", 1);
        }

        print_ascii(ptr + i, (size - i < 16) ? size - i : 16);
        write(1, "\n", 1);
        i += 16;
    }
    return addr;
}

exercises.tests:
int main() {
    char str[] = "Hello, memory viewer!\nLet's test this function.";
    ft_print_memory(str, sizeof(str));
    return 0;
    // Expected output: formatted memory dump
}

