unsigned int ft_strlcat(char *dest, char *src, unsigned int size) {
    unsigned int i = 0;
    unsigned int j = 0;
    while (i < size && dest[i]) i++;
    while ((i + j + 1) < size && src[j]) {
        dest[i + j] = src[j];
        j++;
    }
    if (i < size) dest[i + j] = '\0';
    while (src[j]) j++;
    return i + j;
}

