int is_valid_base(char *base) {
    int i, j;
    int len = ft_strlen(base);
    if (len < 2) return 0;
    for (i = 0; i < len; i++) {
        if (base[i] == '+' || base[i] == '-' || base[i] <= 32 || base[i] > 126)
            return 0;
        for (j = i + 1; j < len; j++) {
            if (base[i] == base[j]) return 0;
        }
    }
