void ft_putnbr_base(int nbr, char *base) {
    long nb = nbr;
    int len = ft_strlen(base);
    if (!is_valid_base(base)) return;
    if (nb < 0) {
        write(1, "-", 1);
        nb = -nb;
    }
    if (nb >= len)
        ft_putnbr_base(nb / len, base);
    write(1, &base[nb % len], 1);
}

