        if (base[i] == '+' || base[i] == '-' || base[i] <= 32 || base[i] > 126)
            return 0;
        for (j = i + 1; j < len; j++) {
            if (base[i] == base[j]) return 0;
        }
    }
    return 1;
}

int base_index(char c, char *base) {
    int i = 0;
    while (base[i]) {
        if (base[i] == c) return i;
        i++;
    }
    return -1;
}

int ft_atoi_base(char *str, char *base) {
    int i = 0, sign = 1, result = 0;
    int len;
    if (!is_valid_base(base)) return 0;
    len = ft_strlen(base);
    while (str[i] == ' ' || (str[i] >= 9 && str[i] <= 13)) i++;
    while (str[i] == '+' || str[i] == '-') {
        if (str[i] == '-') sign *= -1;
        i++;
    }
    int index;
    while ((index = base_index(str[i], base)) != -1) {
        result = result * len + index;
        i++;
    }
    return result * sign;
}

