int ft_strlen(char *str)
{
    int len = 0;
    while (str[len])
        len++;
    return len;
}

char *ft_strcat(char *dest, char *src)
{
    int i = 0;
    int j = 0;
    while (dest[i])
        i++;
    while (src[j])
        dest[i++] = src[j++];
    dest[i] = '\0';
    return dest;
}

char *ft_strjoin(int size, char **strs, char *sep)
{
    int len = 0, i;
    char *res;

    if (size == 0)
    {
        res = (char *)malloc(sizeof(char));
        if (res)
            res[0] = '\0';
        return res;
    }

    for (i = 0; i < size; i++)
        len += ft_strlen(strs[i]);
    len += ft_strlen(sep) * (size - 1);

    res = (char *)malloc(sizeof(char) * (len + 1));
    if (!res)
        return NULL;
    res[0] = '\0';

    for (i = 0; i < size; i++)
    {
        ft_strcat(res, strs[i]);
        if (i < size - 1)
            ft_strcat(res, sep);
    }
    return res;
}

