}

#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <string.h>

void print_hex_line(unsigned char *buf, int len, int offset) {
    printf("%08x  ", offset);
    for (int i = 0; i < 16; i++) {
        if (i < len)
            printf("%02x ", buf[i]);
        else
            printf("   ");
        if (i == 7)
            printf(" ");
    }
    printf(" |\n");
}

int main(int argc, char **argv) {
    if (argc != 2) return 1;
    int fd = open(argv[1], O_RDONLY);
    if (fd < 0) return 1;

    unsigned char buf[16], prev[16];
    int offset = 0, n, same = 0;

    while ((n = read(fd, buf, 16)) > 0) {
        if (same && memcmp(buf, prev, 16) == 0) {
            printf("*\n");
            lseek(fd, 16, SEEK_CUR);
            offset += 16;
            continue;
        }
        print_hex_line(buf, n, offset);
        memcpy(prev, buf, 16);
        same = 1;
        offset += n;
    }
    close(fd);
    return 0;
}

