int ft_is_sort(int *tab, int length, int (*f)(int, int)) {
    int asc = 1, desc = 1;
    for (int i = 0; i < length - 1; i++) {
        if (f(tab[i], tab[i + 1]) > 0) asc = 0;
        if (f(tab[i], tab[i + 1]) < 0) desc = 0;
    }
    return asc || desc;
}

