#include "ft_list.h"

void ft_list_sort(t_list **begin_list, int (*cmp)())
{
    if (!begin_list || !*begin_list)
        return;
    t_list *i = *begin_list;
    while (i)
    {
        t_list *j = i->next;
        while (j)
        {
            if (cmp(i->data, j->data) > 0)
            {
                void *temp = i->data;
                i->data = j->data;
                j->data = temp;
            }
            j = j->next;
        }
        i = i->next;
    }
}

