#include "ft_list.h"

void ft_list_reverse_fun(t_list *begin_list)
{
    if (!begin_list)
        return;

    t_list *i = begin_list;
    int size = 0;
    while (i)
    {
        size++;
        i = i->next;
    }

    t_list *arr[size];
    i = begin_list;
    for (int j = 0; j < size; j++)
    {
        arr[j] = i;
        i = i->next;
    }

    for (int j = 0; j < size / 2; j++)
    {
        void *tmp = arr[j]->data;
        arr[j]->data = arr[size - j - 1]->data;
        arr[size - j - 1]->data = tmp;
    }
}

