#include <stdlib.h>
#include "btree.h"

void btree_insert_data(t_btree **root, void *item, int (*cmpf)(void *, void *))
{
    if (!*root)
    {
        *root = btree_create_node(item);
        return;
    }
    if (cmpf(item, (*root)->item) < 0)
        btree_insert_data(&((*root)->left), item, cmpf);
    else
        btree_insert_data(&((*root)->right), item, cmpf);
}

