#include <stdlib.h>
#include "btree.h"

void btree_apply_level(t_btree *root, int level, int *first, void (*applyf)(void *, int, int))
{
    if (!root)
        return;
    if (level == 0)
        applyf(root->item, level, (*first)-- == 0);
    else
    {
        btree_apply_level(root->left, level - 1, first, applyf);
        btree_apply_level(root->right, level - 1, first, applyf);
    }
}

int btree_level_count(t_btree *root);

void btree_apply_by_level(t_btree *root, void (*applyf)(void *, int, int))
{
    int levels = btree_level_count(root);
    for (int i = 0; i < levels; i++)
    {
        int first = 0;
        btree_apply_level(root, i, &first, applyf);
    }
}

